using backend.Models;

namespace backend.Strategies
{
    public struct StrategyContext
    {
        public double CurrentPrice { get; set; }
        public double YtdVwap { get; set; }
        public double Poc { get; set; }
        public double[] Obv { get; set; }
        public double[] Cmf { get; set; }
        public double VolPctRank { get; set; }
        public double RsRank { get; set; }
        public double RsSharpe { get; set; }
        public double ZScore { get; set; }
        public double ChandelierExit { get; set; }
        public double Discount52W { get; set; }

        // Added for JustNifty Strategy
        public double Ema8 { get; set; }
        public double Ema10 { get; set; }
        public double Ema21 { get; set; }
        public double Ema50 { get; set; }
        public double Ema200 { get; set; }
        public double Rsi14 { get; set; }
        public double MacdLine { get; set; }
        public double MacdSignal { get; set; }
        public double Jnsar { get; set; }
    }

    public interface IStrategy
    {
        string Name { get; }
        bool Evaluate(StrategyContext context);
        string GetLogic(StrategyContext context);
        bool ShouldExit(StrategyContext context, BacktestTrade openTrade);
    }
}

using System;
using backend.Models;

namespace backend.Strategies
{
    public class JustNiftyStrategy : IStrategy
    {
        public string Name => "JustNifty Positional";

        public bool Evaluate(StrategyContext context)
        {
            // 1. 200 EMA Major Bias: Price must be above 200 EMA for a long positional trade.
            if (context.CurrentPrice <= context.Ema200) return false;

            // 2. 8 & 21 MA Crossover: 8 EMA should be above 21 EMA (bullish momentum).
            if (context.Ema8 <= context.Ema21) return false;

            // 3. J10SAR Base (10-Day EMA): Price should be above 10-Day EMA.
            if (context.CurrentPrice <= context.Ema10) return false;

            // 4. Trend Indicator Confirmation: MACD Line should be above Signal Line.
            if (context.MacdLine <= context.MacdSignal) return false;

            return true;
        }

        public string GetLogic(StrategyContext context)
        {
            // J10SAR Envelope upper band for part booking (10-Day EMA + 2.5%)
            double envelopeUpper = Math.Round(context.Ema10 * 1.025, 2);

            return $"JustNifty Positional: Bullish Bias (Price > 200EMA). " +
                   $"8 & 21 EMA in positive crossover. " +
                   $"Price is above J10SAR (10 EMA). " +
                   $"MACD is bullish. " +
                   $"Target Envelope Upper Band (2.5%) at {envelopeUpper} for part booking.";
        }

        public bool ShouldExit(StrategyContext context, BacktestTrade openTrade)
        {
            return context.CurrentPrice < context.Ema10 || context.CurrentPrice < context.Ema21;
        }
    }
}

using System;
using System.Linq;
using backend.Models;

namespace backend.Strategies
{
    public class JustNiftyHctStrategy : IStrategy
    {
        public string Name => "JustNifty HCT";

        public bool Evaluate(StrategyContext context)
        {
            // JustNifty HCT: Price > 200 EMA, and short term EMA crossover
            double currentPrice = context.CurrentPrice;
            double ema200 = context.Ema200;
            double ema21 = context.Ema21; // Using 21 EMA

            return currentPrice > ema200 && currentPrice > ema21;
        }

        public string GetLogic(StrategyContext context)
        {
            return "JustNifty HCT: Price above 200 EMA and short-term EMA.";
        }

        public bool ShouldExit(StrategyContext context, BacktestTrade openTrade)
        {
            return context.CurrentPrice < context.Ema21;
        }
    }
}

using System;
using System.Linq;
using backend.Models;

namespace backend.Strategies
{
    public class JustNiftyLrhrStrategy : IStrategy
    {
        public string Name => "JustNifty LRHR";

        public bool Evaluate(StrategyContext context)
        {
            // JustNifty LRHR: Pullback to Fib retracement levels
            double currentPrice = context.CurrentPrice;
            double ema200 = context.Ema200;

            // Simplified proxy: price is near but above 200 EMA
            return currentPrice > ema200 && currentPrice < ema200 * 1.05;
        }

        public string GetLogic(StrategyContext context)
        {
            return "JustNifty LRHR: Price retracing to 200 EMA support.";
        }

        public bool ShouldExit(StrategyContext context, BacktestTrade openTrade)
        {
            return context.CurrentPrice < context.Ema200;
        }
    }
}

using backend.Models;

namespace backend.Strategies
{
    public class HctStrategy : IStrategy
    {
        public string Name => "Quant HCT Pullback";

        public bool Evaluate(StrategyContext context)
        {
            int last = context.Obv.Length - 1;

            // Wait for 20 days for OBV trend
            if (last < 20) return false;

            return (context.CurrentPrice >= context.YtdVwap * 0.97 && context.CurrentPrice <= context.YtdVwap * 1.05 ||
                    context.CurrentPrice >= context.Poc * 0.97 && context.CurrentPrice <= context.Poc * 1.05) &&
                   context.Obv[last] > context.Obv[last - 20] &&
                   context.Cmf[last] > 0 &&
                   context.VolPctRank < 30 &&
                   context.RsRank > 80 &&
                   context.ZScore >= -1.0 && context.ZScore <= 0.5 &&
                   context.CurrentPrice > context.ChandelierExit;
        }

        public string GetLogic(StrategyContext context)
        {
            return "HCT (Institutional Pullback): Price near VWAP/POC, Positive CMF, High RS, Volatility Compressed. | ";
        }

        public bool ShouldExit(StrategyContext context, BacktestTrade openTrade)
        {
            return context.CurrentPrice < context.ChandelierExit;
        }
    }
}

using backend.Models;

namespace backend.Strategies
{
    public class LrhrStrategy : IStrategy
    {
        public string Name => "Quant LRHR Base";

        public bool Evaluate(StrategyContext context)
        {
            int last = context.Obv.Length - 1;

            if (last < 10) return false;

            return context.ZScore < -1.0 &&
                   context.Discount52W >= 0.25 &&
                   context.Cmf[last] > 0 && context.Cmf[last - 5] <= 0 &&
                   context.Obv[last] > context.Obv[last - 10] &&
                   context.VolPctRank < 50 &&
                   context.CurrentPrice > context.Poc;
        }

        public string GetLogic(StrategyContext context)
        {
            return "LRHR (Institutional Base): Deep Value (Z < -1, >25% pullback), Institutional Accumulation (CMF/OBV Inflection). | ";
        }

        public bool ShouldExit(StrategyContext context, BacktestTrade openTrade)
        {
            return context.CurrentPrice < context.Poc;
        }
    }
}

